package org.apache.commons.math.stat.correlation;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.stat.correlation.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.stat.correlation.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.stat.correlation.PearsonsCorrelation;
import org.apache.commons.math.stat.correlation.Covariance;
import org.apache.commons.math.linear.RealMatrix;
import org.apache.commons.math.linear.BlockRealMatrix;

import static org.junit.Assert.assertTrue;

public class StepDefs {

    private PearsonsCorrelation pearsonsCorrelation;
    private RealMatrix correlationPValues;

    @Given("I have a PearsonsCorrelation instance")
    public void i_have_a_PearsonsCorrelation_instance() {
        // Create a small sample dataset for testing purposes
        double[][] data = new double[120][2];

        // Fill with strongly correlated data with slight perturbation to avoid exact correlation issues
        for (int i = 0; i < 120; i++) {
            double x = i;
            double y = i + (Math.random() * 0.01); // slight perturbation
            data[i][0] = x;
            data[i][1] = y;
        }

        try {
            pearsonsCorrelation = new PearsonsCorrelation(data);
        } catch (Exception e) {
            throw new RuntimeException("Failed to create PearsonsCorrelation instance", e);
        }
    }

    @Given("a dataset with 120 pairs of (x, y) values")
    public void a_dataset_with_pairs_of_x_y_values() {
        // This step is covered in the previous method
        // Dataset is already prepared
    }

    @Given("the data exhibits a very strong positive correlation where y is slightly perturbed from x")
    public void the_data_exhibits_a_very_strong_positive_correlation_where_y_is_slightly_perturbed_from_x() {
        // Data structure already reflects this condition
        // y values are slightly perturbed version of x values
    }

    @When("I compute the p-value matrix for the correlation")
    public void i_compute_the_p_value_matrix_for_the_correlation() {
        try {
            correlationPValues = pearsonsCorrelation.getCorrelationPValues();
        } catch (Exception e) {
            throw new RuntimeException("Failed to compute p-values", e);
        }
    }

    @Then("the p-value for the correlation between x and y should be strictly greater than 0.0")
    public void the_p_value_for_the_correlation_between_x_and_y_should_be_strictly_greater_than() {
        try {
            // Check p-value between first and second variable (index 0 and 1)
            double pValue = correlationPValues.getEntry(0, 1);

            System.out.println("Computed p-value: " + pValue);

            // Assert that p-value is greater than 0.0 (this should fail in buggy version)
            assertTrue("P-value should be strictly greater than 0.0", pValue > 0.0);
        } catch (Exception e) {
            throw new RuntimeException("Failed to validate p-value", e);
        }
    }
}

